import { redirect } from "next/navigation";
import { resolveActiveModules } from "@core/navigation/moduleResolver";
import { hasModules } from "@core/navigation/hasModules";
import { productConfig } from "@/product.config";
import { modulesRegistry } from "@/modules.registry";

export default function Home() {
    const items = resolveActiveModules({
        config: productConfig,
        registry: modulesRegistry
    });
    
    const modulesActive = hasModules(items);

    if (modulesActive) {
        redirect("/dashboard");
    }

    // Si no hay módulos instalados, el punto de entrada es /panel
    redirect("/panel");
}
